import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';

// Core Identity & Layout
import Navbar from './components/Navbar';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import DashboardPage from './pages/DashboardPage';
import GeneratePage from './pages/GeneratePage';

// Context & Theme
import { useAuth } from './context/AuthContext';
import { useTheme } from './context/ThemeContext';

/**
 * 🛡️ Security Gate: ProtectedRoute
 * Maintains middle-alignment during loading states.
 */
const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-[#0a0a0a]">
       <div className="w-12 h-12 border-2 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin" />
    </div>
  );
  return user ? children : <Navigate to="/login" />;
};

function App() {
  return (
    /* h-screen ensures the Dark Charcoal background covers the full viewport */
    <div className="min-h-screen flex flex-col transition-colors duration-500 selection:bg-emerald-500/30">

      {/* Institutional Notifications */}
      <Toaster position="bottom-right" />

      <Navbar />

      {/* 🎯 THE CENTERING ENGINE:
          flex-grow pulls the main area to fill space.
          items-center and justify-center force content to the exact middle. */}
      <main className="flex-grow flex flex-col items-center justify-center px-4 py-12">

        {/* max-w-7xl provides a standard gutter for the dashboard */}
        <div className="w-full max-w-7xl flex justify-center items-center">
          <Routes>
            {/* Public Gates: Small and Centered via terminal-card class */}
            <Route path="/login" element={<LoginPage />} />
            <Route path="/register" element={<RegisterPage />} />

            {/* Secure Infrastructure */}
            <Route 
              path="/dashboard" 
              element={<ProtectedRoute><DashboardPage /></ProtectedRoute>} 
            />
            <Route 
              path="/generate" 
              element={<ProtectedRoute><GeneratePage /></ProtectedRoute>} 
            />

            {/* System Redirection */}
            <Route path="/" element={<Navigate to="/login" replace />} />
            <Route path="*" element={<Navigate to="/login" replace />} />
          </Routes>
        </div>
      </main>

      {/* Institutional Texture: Fixed CRT Scanlines */}
      <div className="fixed inset-0 pointer-events-none z-[999] opacity-[0.03] bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]" />
    </div>
  );
}

export default App;
